const M = 'http://mlflow:5050/api/2.0/mlflow';
const body = $input.item.json.body;
const action = body.action;

try {

if (!action) throw new Error('action required: list, get, runs, metrics, delete');

async function post(path, data) {
  var r = await fetch(M + path, {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});
  if (!r.ok) throw new Error('MLflow ' + r.status + ': ' + (await r.text()));
  return r.json();
}

async function apiGet(path) {
  var r = await fetch(M + path);
  if (!r.ok) throw new Error('MLflow ' + r.status + ': ' + (await r.text()));
  return r.json();
}

if (action === 'list') {
  var searchRes = await post('/experiments/search', {
    max_results: body.limit || 100
  });
  var experiments = (searchRes.experiments || []).map(function(exp) {
    return {
      experiment_id: exp.experiment_id,
      name: exp.name,
      lifecycle_stage: exp.lifecycle_stage,
      creation_time: Number(exp.creation_time),
      last_update_time: Number(exp.last_update_time),
      artifact_location: exp.artifact_location
    };
  });
  return {action: 'list', experiments: experiments, count: experiments.length};
}

if (action === 'get') {
  var expId = body.experiment_id;
  var expName = body.experiment_name;
  if (!expId && !expName) throw new Error('experiment_id or experiment_name required');
  var exp;
  if (expId) {
    var expRes = await apiGet('/experiments/get?experiment_id=' + encodeURIComponent(expId));
    exp = expRes.experiment;
  } else {
    var expRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent(expName));
    exp = expRes.experiment;
    expId = exp.experiment_id;
  }
  var limit = body.limit || 10;
  var searchRes = await post('/runs/search', {
    experiment_ids: [expId],
    max_results: limit,
    order_by: ['start_time DESC']
  });
  var runs = (searchRes.runs || []).map(function(run) {
    var info = run.info || {};
    var params = {};
    (run.data && run.data.params || []).forEach(function(p) { params[p.key] = p.value; });
    var metrics = {};
    (run.data && run.data.metrics || []).forEach(function(m) { metrics[m.key] = m.value; });
    return {
      run_id: info.run_id,
      run_name: info.run_name || '',
      status: info.status,
      start_time: Number(info.start_time),
      end_time: Number(info.end_time),
      params: params,
      metrics: metrics
    };
  });
  return {
    action: 'get',
    experiment_id: expId,
    name: exp.name,
    lifecycle_stage: exp.lifecycle_stage,
    creation_time: Number(exp.creation_time),
    runs: runs,
    run_count: runs.length
  };
}

if (action === 'runs') {
  var experimentIds = body.experiment_ids;
  if (!experimentIds || !Array.isArray(experimentIds)) throw new Error('experiment_ids array required');
  var searchBody = {
    experiment_ids: experimentIds,
    max_results: body.limit || 25
  };
  if (body.filter) searchBody.filter = body.filter;
  if (body.order_by) searchBody.order_by = body.order_by;
  var searchRes = await post('/runs/search', searchBody);
  var runs = (searchRes.runs || []).map(function(run) {
    var info = run.info || {};
    var params = {};
    (run.data && run.data.params || []).forEach(function(p) { params[p.key] = p.value; });
    var metrics = {};
    (run.data && run.data.metrics || []).forEach(function(m) { metrics[m.key] = m.value; });
    return {
      run_id: info.run_id,
      run_name: info.run_name || '',
      experiment_id: info.experiment_id,
      status: info.status,
      start_time: Number(info.start_time),
      end_time: Number(info.end_time),
      params: params,
      metrics: metrics
    };
  });
  return {action: 'runs', runs: runs, count: runs.length};
}

if (action === 'metrics') {
  var runId = body.run_id;
  var metricKey = body.metric_key;
  if (!runId || !metricKey) throw new Error('run_id and metric_key required');
  var histRes = await apiGet('/metrics/get-history?run_id=' + encodeURIComponent(runId) + '&metric_key=' + encodeURIComponent(metricKey));
  var history = (histRes.metrics || []).map(function(m) {
    return {value: m.value, timestamp: Number(m.timestamp), step: m.step};
  });
  return {action: 'metrics', run_id: runId, metric_key: metricKey, history: history, count: history.length};
}

if (action === 'delete') {
  var expId = body.experiment_id;
  if (!expId) throw new Error('experiment_id required');
  await post('/experiments/delete', {experiment_id: expId});
  return {action: 'delete', experiment_id: expId, status: 'deleted'};
}

throw new Error('Unknown action: ' + action);

} catch(e) {
  var msg = e.message || String(e);
  if (e.response && e.response.data) msg += ' | ' + JSON.stringify(e.response.data);
  var status = 400;
  if (e.response && e.response.status === 404) status = 404;
  if (msg.indexOf('RESOURCE_DOES_NOT_EXIST') !== -1) status = 404;
  return {error: true, message: msg, action: action || 'unknown', _status: status};
}
